import React, { useState, useRef, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  Stepper,
  Step,
  StepLabel,
  StepButton,
  LinearProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import EditIcon from '@mui/icons-material/Edit';
import SendIcon from '@mui/icons-material/Send';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import TipsAndUpdatesIcon from '@mui/icons-material/TipsAndUpdates';
import VerifiedIcon from '@mui/icons-material/Verified';
import CelebrationOutlinedIcon from '@mui/icons-material/CelebrationOutlined';
import { keyframes } from '@mui/system';
import clumsyDoodle from '../assets/clumsy.png';

const TestimonialMascot = ({ size = 'medium', color = 'primary' }) => {
  const theme = useTheme();
  const sizeMap = {
    small: { width: 40, height: 40, quoteSize: 'small' },
    medium: { width: 60, height: 60, quoteSize: 'medium' },
    large: { width: 80, height: 80, quoteSize: 'large' }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Speech bubble shape */}
      <Box
        sx={{
          width: '100%',
          height: '100%',
          borderRadius: '50%',
          background: theme => theme.palette[color].main,
          position: 'relative',
          '&::after': {
            content: '""',
            position: 'absolute',
            bottom: '-10px',
            right: '10px',
            width: '20px',
            height: '20px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.5)'
          },
          '&::before': {
            content: '""',
            position: 'absolute',
            bottom: '-18px',
            right: '0',
            width: '15px',
            height: '15px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.3)'
          }
        }}
      />

      {/* Quote icon */}
      <FormatQuoteIcon 
        sx={{ 
          position: 'absolute', 
          color: 'white',
          transform: 'rotate(180deg)',
          fontSize: dims.quoteSize === 'small' ? '1.5rem' : 
                   dims.quoteSize === 'medium' ? '2rem' : '2.5rem'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          left: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          right: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '30%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '20px',
          height: '10px',
          borderBottomLeftRadius: '10px',
          borderBottomRightRadius: '10px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const TestimonialStarMascot = ({ size = 'medium', color = 'primary' }) => {
  const sizeMap = {
    small: { width: 40, height: 40 },
    medium: { width: 60, height: 60 },
    large: { width: 80, height: 80 }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Star shape */}
      <StarIcon 
        sx={{ 
          position: 'absolute',
          width: '100%',
          height: '100%',
          color: theme => theme.palette[color].main,
          filter: 'drop-shadow(0 2px 5px rgba(0,0,0,0.2))'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          left: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          right: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '35%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '16px',
          height: '8px',
          borderBottomLeftRadius: '8px',
          borderBottomRightRadius: '8px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const subtleShakeAnimation = keyframes`
  0% { transform: translateX(0); }
  25% { transform: translateX(-2px); }
  50% { transform: translateX(0); }
  75% { transform: translateX(2px); }
  100% { transform: translateX(0); }
`;

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [activeStep, setActiveStep] = useState(0);
  const [completed, setCompleted] = useState({});
  const [originalScores, setOriginalScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [enhancedScores, setEnhancedScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [spotlightActive, setSpotlightActive] = useState(false);
  const [shakeEnhanceButton, setShakeEnhanceButton] = useState(false);

  const steps = [
    'Enter original testimonial',
    'Get AI enhancement',
    'Client verification'
  ];

  const originalText = "The coaching was good. I learned some things that helped me.";
  const enhancedText = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  const handleStep = (step) => () => {
    setActiveStep(step);

    // Mark previous steps as completed
    const newCompleted = {...completed};
    for (let i = 0; i < step; i++) {
      newCompleted[i] = true;
    }
    setCompleted(newCompleted);
  };

  const handleNext = () => {
    const newCompleted = {...completed};
    newCompleted[activeStep] = true;
    setCompleted(newCompleted);
    setActiveStep((prevActiveStep) => prevActiveStep + 1);
  };

  const handleReset = () => {
    setActiveStep(0);
    setCompleted({});
    setOriginalScores({ emotional: 0, specificity: 0, credibility: 0 });
    setEnhancedScores({ emotional: 0, specificity: 0, credibility: 0 });
    setSpotlightActive(false);
  };

  const getScoreColor = (score) => {
    if (score < 50) return 'error.main';
    if (score < 75) return 'warning.main';
    return 'success.main';
  };

  const handleTryDemo = () => {
    setSpotlightActive(true);

    // Shake the enhance button
    setShakeEnhanceButton(true);
    setTimeout(() => setShakeEnhanceButton(false), 1500);

    // Scroll to demo on mobile
    if (isMobile && demoRef.current) {
      demoRef.current.scrollIntoView({ 
        behavior: 'smooth',
        block: 'center'
      });
    }

    // Auto-dismiss spotlight after 3 seconds
    setTimeout(() => {
      setSpotlightActive(false);
    }, 3000);
  };

  const demoRef = useRef(null);

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box component="section" sx={{ 
        position: 'relative',
        pt: { xs: 10, md: 12 }, 
        pb: { xs: 8, md: 10 },
        overflow: 'hidden',
        background: 'linear-gradient(135deg, #f5f7fa 0%, #e8eaec 100%)',
      }}>
        <Container>
          <Grid container spacing={4} alignItems="center">
            <Grid item xs={12} md={6}>
              <Typography 
                variant="h1" 
                sx={{ 
                  mb: 2,
                  color: '#1a2a3a',
                  fontWeight: 700,
                }}
              >
                Hi, I'm [Your Name]
              </Typography>
              <Typography 
                variant="h4" 
                sx={{ 
                  mb: 3,
                  color: '#2c3e50',
                  fontWeight: 500,
                }}
              >
                Full-Stack Developer
              </Typography>
              <Typography 
                variant="body1" 
                paragraph 
                sx={{ 
                  mb: 4,
                  color: '#34495e',
                  fontSize: '1.1rem',
                  maxWidth: '90%'
                }}
              >
                I build responsive, accessible web applications with modern technologies.
                Passionate about clean code and intuitive user experiences.
              </Typography>
              <Stack direction="row" spacing={2}>
                <Button 
                  variant="contained" 
                  size="large"
                  component={RouterLink}
                  to="/contact"
                  sx={{
                    background: 'linear-gradient(45deg, #e74c3c 30%, #ff7675 90%)',
                    fontWeight: 600,
                    px: 3,
                    '&:hover': {
                      background: 'linear-gradient(45deg, #c0392b 30%, #e74c3c 90%)',
                    }
                  }}
                >
                  Get In Touch
                </Button>
                <Button 
                  variant="outlined" 
                  size="large"
                  component={RouterLink}
                  to="/projects"
                  sx={{
                    borderColor: '#e74c3c',
                    color: '#e74c3c',
                    fontWeight: 600,
                    px: 3,
                    '&:hover': {
                      borderColor: '#c0392b',
                      background: 'rgba(231, 76, 60, 0.04)',
                    }
                  }}
                >
                  View Projects
                </Button>
              </Stack>
            </Grid>

            <Grid item xs={12} md={6} sx={{ 
              display: 'flex', 
              justifyContent: 'center',
              position: 'relative',
            }}>
              <Box
                component="img"
                src={clumsyDoodle}
                alt="Developer juggling papers and code"
                sx={{ 
                  width: { xs: '80%', md: '90%' },
                  maxWidth: 400,
                  filter: 'drop-shadow(0px 10px 15px rgba(0, 0, 0, 0.1))',
                  animation: 'float 6s ease-in-out infinite',
                  '@keyframes float': {
                    '0%': {
                      transform: 'translateY(0px)',
                    },
                    '50%': {
                      transform: 'translateY(-20px)',
                    },
                    '100%': {
                      transform: 'translateY(0px)',
                    },
                  },
                }}
              />

              <Box sx={{
                position: 'absolute',
                width: '100%',
                height: '100%',
                top: 0,
                left: 0,
                pointerEvents: 'none',
                zIndex: -1,
                opacity: 0.5,
                background: 'radial-gradient(circle at 70% 50%, rgba(231, 76, 60, 0.1) 0%, rgba(231, 76, 60, 0) 50%)',
              }} />
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10, bgcolor: '#F8F9FF' }}>
        <Container maxWidth="lg">
          <Typography 
            variant="h3" 
            align="center" 
            gutterBottom
            sx={{ fontWeight: 700 }}
          >
            How It Works
          </Typography>

          <Typography 
            variant="subtitle1" 
            align="center" 
            color="text.secondary"
            sx={{ mb: 8, maxWidth: 700, mx: 'auto' }}
          >
            Transform bland testimonials into powerful stories in three simple steps
          </Typography>

          <Grid container spacing={4}>
            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get AI-enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Our AI extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  3
                </Box>
                <Typography variant="h5" gutterBottom>
                  One-click client approval
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Send a verification link to your client for instant approval with a single click.
                </Typography>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* CTA Section */}
      <Box 
        sx={{ 
          py: 10,
          transition: 'all 0.5s ease',
          filter: spotlightActive ? 'blur(2px)' : 'none',
          opacity: spotlightActive ? 0.3 : 1
        }}
      >
        <Container maxWidth="md">
          <Card 
            sx={{ 
              p: { xs: 4, md: 6 },
              background: 'linear-gradient(135deg, #5D5FEF 0%, #7879F1 100%)',
              color: 'white',
              textAlign: 'center',
              position: 'relative',
              overflow: 'hidden',
              borderRadius: 4
            }}
          >
            <Box 
              sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                opacity: 0.1,
                backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)',
                backgroundSize: '20px 20px'
              }}
            />

            <Typography variant="h3" gutterBottom>
              Ready to transform your testimonials?
            </Typography>
            <Typography variant="subtitle1" sx={{ mb: 4, opacity: 0.9, maxWidth: 600, mx: 'auto' }}>
              Start free, no credit card required. Upgrade when you need more.
            </Typography>
            <Button 
              variant="contained" 
              size="large"
              component={RouterLink}
              to="/enhance"
              sx={{ 
                px: 4, 
                py: 1.5,
                bgcolor: 'white',
                color: 'primary.main',
                '&:hover': {
                  bgcolor: 'rgba(255, 255, 255, 0.9)'
                }
              }}
              disabled={spotlightActive}
            >
              Get Started Now
            </Button>
          </Card>
        </Container>
      </Box>
    </Box>
  );
};

export default HomePage;
